\u09c1\\\\u09a4 \\\\u0995\\\\u09be\\\\u09b0\\\\u09cd\\\\u09af\\\\u0995\\\\u09b0 \\\\u09aa\\\\u09a6\\\\u0995\\\\u09cd\\\\u09b7\\\\u09c7\\\\u09aa \\\\u09a8\\\\u09c7\\\\u0993\\\\u09af\\\\u09bc\\\\u09be\\\\u09b0 \\\\u0986\\\\u09b6\\\\u09cd\\\\u09ac\\\\u09be\\\\u09b8 \\\\u09a6\\\\u09bf\\\\u09af\\\\u09bc\\\\u09c7\\\\u099b\\\\u09c7\\\\u0964 \\\\u09a6\\\\u09c7\\\\u09b6\\\\u09c7\\\\u09b0 \\\\u09b8\\\\u09be\\\\u09a7\\\\u09be\\\\u09b0\\\\u09a3 \\\\u09ae\\\\u09be\\\\u09a8\\\\u09c1\\\\u09b7 \\\\u098f\\\\u0987 \\\\u09ac\\\\u09bf\\\\u09b7\\\\u09af\\\\u09bc\\\\u09c7 \\\\u0997\\\\u09ad\\\\u09c0\\\\u09b0 \\\\u0986\\\\u0997\\\\u09cd\\\\u09b0\\\\u09b9 \\\\u09a6\\\\u09c7\\\\u0996\\\\u09be\\\\u099a\\\\u09cd\\\\u099b\\\\u09c7\\\\u09a8 \\\\u098f\\\\u09ac\\\\u0982 \\\\u09b8\\\\u09be\\\\u09ae\\\\u09be\\\\u099c\\\\u09bf\\\\u0995 \\\\u09ae\\\\u09be\\\\u09a7\\\\u09cd\\\\u09af\\\\u09ae\\\\u09c7 \\\\u09ac\\\\u09cd\\\\u09af\\\\u09be\\\\u09aa\\\\u0995 \\\\u0986\\\\u09b2\\\\u09cb\\\\u099a\\\\u09a8\\\\u09be \\\\u099a\\\\u09b2\\\\u099b\\\\u09c7\\\\u0964 \\\\u0986\\\\u0997\\\\u09be\\\\u09ae\\\\u09c0 \\\\u09a6\\\\u09bf\\\\u09a8\\\\u09c7 \\\\u098f\\\\u0987 \\\\u09ac\\\\u09bf\\\\u09b7\\\\u09af\\\\u09bc\\\\u09c7 \\\\u0986\\\\u09b0\\\\u0993 \\\\u09ac\\\\u09bf\\\\u09b8\\\\u09cd\\\\u09a4\\\\u09be\\\\u09b0\\\\u09bf\\\\u09a4 \\\\u09a4\\\\u09a5\\\\u09cd\\\\u09af \\\\u099c\\\\u09be\\\\u09a8\\\\u09be \\\\u09af\\\\u09be\\\\u09ac\\\\u09c7 \\\\u09ac\\\\u09b2\\\\u09c7 \\\\u09b8\\\\u09c2\\\\u09a4\\\\u09cd\\\\u09b0 \\\\u099c\\\\u09be\\\\u09a8\\\\u09bf\\\\u09af\\\\u09bc\\\\u09c7\\\\u099b\\\\u09c7\\\\u0964<\\\\\\/p><p>\\\\u09ac\\\\u09be\\\\u0982\\\\u09b2\\\\u09be\\\\u09a6\\\\u09c7\\\\u09b6\\\\u09c7\\\\u09b0 \\\\u09b8\\\\u0982\\\\u09ac\\\\u09be\\\\u09a6 \\\\u09ae\\\\u09be\\\\u09a7\\\\u09cd\\\\u09af\\\\u09ae\\\\u09c7 \\\\u0986\\\\u099c\\\\u0995\\\\u09c7\\\\u09b0 \\\\u098f\\\\u0987 \\\\u0996\\\\u09ac\\\\u09b0\\\\u099f\\\\u09bf \\\\u09ac\\\\u09bf\\\\u09b6\\\\u09c7\\\\u09b7 \\\\u0997\\\\u09c1\\\\u09b0\\\\u09c1\\\\u09a4\\\\u09c